import React from 'react';
import { PERSONAL_INFO, SOCIAL_LINKS } from '../data/portfolioData';
import { Download, Mail, Phone, Linkedin, MapPin } from 'lucide-react';

const HeroSection = () => {
  const handleDownloadResume = () => {
    // Create a link element and trigger download
    const link = document.createElement('a');
    link.href = PERSONAL_INFO.resumeFile;
    link.download = 'Sachin-Lal-CP-Resume.pdf';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <section id="home" className="section-padding bg-gradient-to-br from-primary-50 to-white min-h-screen flex items-center">
      <div className="container-max">
        <div className="grid md:grid-cols-2 gap-12 items-center">
          {/* Text Content */}
          <div className="space-y-6">
            <div className="space-y-4">
              <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold text-gray-900">
                Hi, I'm <span className="text-gradient">{PERSONAL_INFO.name}</span>
              </h1>
              <h2 className="text-xl md:text-2xl text-gray-700 font-medium">
                {PERSONAL_INFO.title}
              </h2>
            </div>

            <div className="space-y-3">
              <div className="flex items-center space-x-3 text-gray-600">
                <Mail size={20} className="text-primary-600" />
                <a href={`mailto:${PERSONAL_INFO.email}`} className="hover:text-primary-600 transition-colors">
                  {PERSONAL_INFO.email}
                </a>
              </div>
              <div className="flex items-center space-x-3 text-gray-600">
                <Phone size={20} className="text-primary-600" />
                <a href={`tel:${PERSONAL_INFO.phone}`} className="hover:text-primary-600 transition-colors">
                  {PERSONAL_INFO.phone}
                </a>
              </div>
              <div className="flex items-center space-x-3 text-gray-600">
                <Linkedin size={20} className="text-primary-600" />
                <a 
                  href={`https://${PERSONAL_INFO.linkedin}`} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="hover:text-primary-600 transition-colors"
                >
                  {PERSONAL_INFO.linkedin}
                </a>
              </div>
              <div className="flex items-center space-x-3 text-gray-600">
                <MapPin size={20} className="text-primary-600" />
                <span>{PERSONAL_INFO.location}</span>
              </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4 pt-4">
              <button
                onClick={handleDownloadResume}
                className="btn-primary flex items-center justify-center space-x-2"
              >
                <Download size={20} />
                <span>Download Resume</span>
              </button>
              <a
                href={SOCIAL_LINKS.linkedin}
                target="_blank"
                rel="noopener noreferrer"
                className="btn-secondary flex items-center justify-center space-x-2"
              >
                <Linkedin size={20} />
                <span>LinkedIn Profile</span>
              </a>
            </div>
          </div>

          {/* Profile Image */}
          <div className="flex justify-center">
            <div className="relative">
              <div className="w-64 h-64 md:w-80 md:h-80 rounded-full overflow-hidden border-4 border-white shadow-2xl">
                <img
                  src={PERSONAL_INFO.profileImage}
                  alt={PERSONAL_INFO.name}
                  className="w-full h-full object-cover"
                  onError={(e) => {
                    // Fallback to a placeholder if image fails to load
                    e.target.src = `https://picsum.photos/seed/${PERSONAL_INFO.name}/400/400.jpg`;
                  }}
                />
              </div>
              {/* Decorative ring */}
              <div className="absolute inset-0 rounded-full border-4 border-primary-200 -z-10 transform scale-110"></div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default HeroSection;
